def summarize(trace):
    tools = {(t["tool"], frozenset(t["args"].items())) for t in trace}
    total_tokens = sum(t["tokens"] for t in trace)
    return {
        "turns": len(trace),
        "distinct_calls": len(tools),
        "tokens": total_tokens,
    }

