clean_trace = [
    {"tool": "search", "args": {"q": "auth"},      "tokens": 180},
    {"tool": "lookup", "args": {"id": 7},          "tokens": 160},
    {"tool": "search", "args": {"q": "billing"},   "tokens": 200},
]

def bug_report(trace):
    fingerprints = {
        (t["tool"], frozenset(t["args"].items())) for t in trace
    }
    looping = False
    for i in range(len(trace) - 2):
        window = trace[i:i + 3]
        first = (window[0]["tool"], frozenset(window[0]["args"].items()))
        if all(
            (t["tool"], frozenset(t["args"].items())) == first
            for t in window
        ):
            looping = True
            break
    return {
        "total_turns": len(trace),
        "distinct_tools_called": len(fingerprints),
        "looping": looping,
        "total_tokens": sum(t["tokens"] for t in trace),
    }

print(bug_report(loop_trace))
print(bug_report(clean_trace))

