def classify(trace):
    for i in range(len(trace) - 2):
        window = trace[i:i + 3]
        first = (window[0]["tool"], frozenset(window[0]["args"].items()))
        if all(
            (t["tool"], frozenset(t["args"].items())) == first
            for t in window
        ):
            return "loop"
    if trace[-1]["tokens"] > 3 * trace[0]["tokens"]:
        return "bloat"
    return "clean"

for tr in [trace_loop, trace_bloat, trace_clean]:
    print(classify(tr))
